const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

// Create a write stream for logging
const accessLogStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Custom token to get username from headers
morgan.token('username', (req) => req.headers['username'] || 'unknown_user');

// Custom token to get IP address
morgan.token('ip', (req) => req.ip || req.connection.remoteAddress);

// Custom token to add any custom header
morgan.token('custom-header', (req) => req.headers['custom-header'] || 'none');

// Setup the logger
app.use(morgan(':ip - :username - :method :url :status - :res[content-length] bytes - :response-time ms - custom-header: :custom-header', { stream: accessLogStream }));

